import{c as e,Q as t,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"CalBench: Evaluating Coordination-Privacy Trade-offs in Multi-Agent LLMs","description":"","frontmatter":{"title":"CalBench: Evaluating Coordination-Privacy Trade-offs in Multi-Agent LLMs","arxiv_id":2605.09823,"authors":"Chelsea Zou, Yiheng Yao, Selena She, Robert D. Hawkins","published":"2026-05-10T00:00:00.000Z","source":"https://arxiv.org/abs/2605.09823","source_tier":"P"},"headers":[],"relativePath":"research/papers/2026-05-10-calbench-coordination-privacy-tradeoffs-2605-09823.md","filePath":"research/papers/2026-05-10-calbench-coordination-privacy-tradeoffs-2605-09823.md","lastUpdated":1779901665000}'),o={name:"research/papers/2026-05-10-calbench-coordination-privacy-tradeoffs-2605-09823.md"};function i(l,a,s,c,d,h){return t(),r("div",null,[...a[0]||(a[0]=[n('<h1 id="calbench-evaluating-coordination-privacy-trade-offs-in-multi-agent-llms" tabindex="-1">CalBench: Evaluating Coordination-Privacy Trade-offs in Multi-Agent LLMs <a class="header-anchor" href="#calbench-evaluating-coordination-privacy-trade-offs-in-multi-agent-llms" aria-label="Permalink to &quot;CalBench: Evaluating Coordination-Privacy Trade-offs in Multi-Agent LLMs&quot;">​</a></h1><p><strong>ArXiv</strong>: 2605.09823 | <strong>Date</strong>: 2026-05-10 | <strong>Authors</strong>: Chelsea Zou, Yiheng Yao, Selena She, Robert D. Hawkins | <strong>Category</strong>: cs.MA</p><h2 id="摘要" tabindex="-1">摘要 <a class="header-anchor" href="#摘要" aria-label="Permalink to &quot;摘要&quot;">​</a></h2><p>首個針對多 agent LLM 協調-隱私權衡的系統性評估框架。核心設定：N 個 agent 各自擁有私有日曆（含現有承諾），必須協作排定 M 個新會議，同時最小化衝突。</p><p><strong>關鍵特性</strong>：「沒有任何 agent 可以存取其他 agent 的私有日曆，但所有 agent 仍必須達成相互一致的決定。」</p><h2 id="核心創新" tabindex="-1">核心創新 <a class="header-anchor" href="#核心創新" aria-label="Permalink to &quot;核心創新&quot;">​</a></h2><h3 id="oracle-解答-dcop-基準" tabindex="-1">Oracle 解答 + DCOP 基準 <a class="header-anchor" href="#oracle-解答-dcop-基準" aria-label="Permalink to &quot;Oracle 解答 + DCOP 基準&quot;">​</a></h3><p>每個場景包含最優 Oracle 解，使協調品質可通過「實際成本 / 最優成本」精確量化。分散式約束最優化（DCOP）基準提供在相同隱私約束下的公平比較。</p><h3 id="隱私評估" tabindex="-1">隱私評估 <a class="header-anchor" href="#隱私評估" aria-label="Permalink to &quot;隱私評估&quot;">​</a></h3><p>日曆條目附有不同敏感度的私有語義上下文，測量 agent 在協商過程中是否無意洩漏任務無關的私有資訊。</p><h2 id="四大評估維度" tabindex="-1">四大評估維度 <a class="header-anchor" href="#四大評估維度" aria-label="Permalink to &quot;四大評估維度&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>描述</th></tr></thead><tbody><tr><td>協調品質</td><td>相對最優解的會議排定效能</td></tr><tr><td>通訊效率</td><td>達成共識所需資源</td></tr><tr><td>公平性</td><td>各參與者間衝突成本的均等分配</td></tr><tr><td>隱私洩漏</td><td>敏感資訊的無意洩漏程度</td></tr></tbody></table><h2 id="與現有基準的區別" tabindex="-1">與現有基準的區別 <a class="header-anchor" href="#與現有基準的區別" aria-label="Permalink to &quot;與現有基準的區別&quot;">​</a></h2><p><strong>強制去中心化</strong>：不允許能力強的單一 agent 替代整個群體，確保評估真實的去中心化協調。</p><p>相比 MultiAgentBench（2503.01935）：</p><ul><li>MultiAgentBench：多種協作競爭場景</li><li>CalBench：聚焦隱私邊界下的協調</li></ul><h2 id="對-workspace-的意義" tabindex="-1">對 Workspace 的意義 <a class="header-anchor" href="#對-workspace-的意義" aria-label="Permalink to &quot;對 Workspace 的意義&quot;">​</a></h2><p>在多 agent 系統中處理敏感資訊時（如用戶資料、API 密鑰、私有業務邏輯），CalBench 提供了評估隱私保護效果的框架模型。</p><p>與 <code>2026-04-13-safeharness-lifecycle-security</code> 互補：</p><ul><li>SafeHarness：執行路徑安全（38% UBR 削減）</li><li>CalBench：多 agent 協調中的資訊隱私</li></ul><h2 id="分類" tabindex="-1">分類 <a class="header-anchor" href="#分類" aria-label="Permalink to &quot;分類&quot;">​</a></h2><p><strong>Benchmark &amp; Evaluation / Safety &amp; Alignment</strong> — 首個協調-隱私權衡評估框架，填補多 agent 系統在隱私約束下協調能力評估的空白。</p>',22)])])}const g=e(o,[["render",i]]);export{u as __pageData,g as default};
